import { useEffect, useRef, useState } from "react";
import { Link } from "react-router-dom";
import "../styles/Home.css";

function Home() {
  const containerRef = useRef(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    // Reveal Observer
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('reveal-active');
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.reveal-trigger').forEach(el => observer.observe(el));

    // Mouse Parallax Effect
    const handleMouseMove = (e) => {
      const { clientX, clientY } = e;
      setMousePos({ x: clientX, y: clientY });

      if (containerRef.current) {
        containerRef.current.style.setProperty('--mx', `${clientX}px`);
        containerRef.current.style.setProperty('--my', `${clientY}px`);
      }
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => {
      observer.disconnect();
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  return (
    <div className="stadium-container" ref={containerRef}>
      <div className="atmospheric-fog"></div>
      <div className="grain-overlay"></div>

      {/* Cinematic Hero */}
      <section className="stadium-hero">
        <div className="parallax-layer bg-layer" style={{ 
          backgroundImage: `url('/home_bg.png')`,
          transform: `translate(${(mousePos.x - window.innerWidth/2) * -0.02}px, ${(mousePos.y - window.innerHeight/2) * -0.02}px) scale(1.1)`
        }}></div>

        <div className="stadium-lights-glow"></div>

        <div className="hero-content-elite">
          <div className="elite-header reveal-trigger">
            <span className="elite-tag">STADIUM PROTOCOL V.2026</span>
            <h1 className="elite-title">
              <span className="title-top">UNLEASH THE</span>
              <span className="title-main">KINETIC <span className="highlight">PULSE</span></span>
            </h1>
            <p className="elite-lead">
              The world's most immersive cricket data engine. High-frequency analytics 
              meets stadium-grade visual fidelity.
            </p>
            <div className="elite-cta-group">
              <Link to="/rankings" className="cta-elite-primary">
                <span className="btn-label">DATA TERMINAL</span>
                <span className="btn-glow"></span>
              </Link>
              <Link to="/compare" className="cta-elite-secondary">
                <span className="btn-label">BATTLE ARENA</span>
              </Link>
            </div>
          </div>
        </div>

        {/* Live Pulse Ticker */}
        <div className="pulse-ticker-container">
          <div className="pulse-label">LIVE SYSTEM FEED</div>
          <div className="pulse-ticker-track">
            {[1, 2].map((i) => (
              <div key={i} className="pulse-ticker-content">
                <div className="ticker-stat">ROHIT SHARMA <span className="val">HOT 📈</span></div>
                <div className="ticker-stat">SYSTEM HEALTH <span className="val">99%</span></div>
                <div className="ticker-stat">VIRAT KOHLI <span className="val">ELITE 🐐</span></div>
                <div className="ticker-stat">NEURAL ENGINE <span className="val pulse">ACTIVE</span></div>
                <div className="ticker-stat">MATCH PREDICTION <span className="val">OPTIMIZED</span></div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Bento Pulse Grid */}
      <section className="stadium-bento-section reveal-trigger">
        <div className="stadium-header">
          <span className="stadium-subtitle">OPERATIONAL MODULES</span>
          <h2 className="stadium-title">COMMAND CENTER</h2>
        </div>

        <div className="stadium-bento-grid">
          {/* Main Visual Bento */}
          <div className="bento-card bento-hero glass-frost">
            <img src="/roko.jpg" alt="Elite Legends" className="hero-bento-img" />
            <div className="bento-shade"></div>
            <div className="bento-info-bottom">
              <span className="bento-badge">PRIME FEATURE</span>
              <h3>THE ROKO ERA</h3>
              <p>Deep-dive into the statistical mastery of Rohit & Kohli.</p>
              <Link to="/players" className="bento-action-btn">ACCESS ROSTER</Link>
            </div>
          </div>

          {/* AI Intelligence Bento */}
          <div className="bento-card bento-ai glass-frost">
            <div className="ai-status">
              <div className="status-orb"></div>
              <span>NEURAL ACTIVE</span>
            </div>
            <div className="bento-icon-box">🤖</div>
            <h3>CRIC-GPT ENGINE</h3>
            <p>Predict match outcomes with AI projections.</p>
            <Link to="/chat" className="bento-link-arrow">INITIALIZE INTERFACE →</Link>
          </div>

          {/* Battle Bento */}
          <div className="bento-card bento-vs glass-frost">
            <div className="vs-logo">VS</div>
            <h3>ARENA MODE</h3>
            <p>1v1 Kinetic comparison engine.</p>
            <Link to="/compare" className="bento-link-arrow">ENTER ARENA →</Link>
          </div>

          {/* Stats Bento */}
          <div className="bento-card bento-stats glass-frost">
              <div className="stat-preview">
                <div className="bar" style={{height: '40%'}}></div>
                <div className="bar" style={{height: '80%'}}></div>
                <div className="bar" style={{height: '60%'}}></div>
